/**
 * 魔法少女猎取计划 — 世界书内置角色魔法名映射表 & 别名映射
 *
 * 世界书条目名格式: `[角色]_真名-魔法少女` / `[角色]_真名-堕落魔法少女`
 * 由于 getWorldbook API 仅返回条目元数据而不返回内容,
 * 魔法名映射使用静态表而非动态解析.
 */

// ── 魔法名映射: 真名 → { 常态魔法名, 堕落魔法名 } ──
export const MAGIC_NAME_MAP: Record<string, { normal: string; fallen: string }> = {
  小银: { normal: '圣咏十字', fallen: '渎神魔女' },
  致远星: { normal: '星海船长', fallen: '亡灵海盗' },
  乌特迦·洛奇: { normal: '安格博达', fallen: '幻惑魔女' },
  爱丽丝: { normal: '仙境迷途', fallen: '梦狱少女' },
  久远琴里: { normal: '幻刻刻影', fallen: '极尽升刻' },
  克劳迪娅: { normal: '血蔷薇', fallen: '夜蔷薇' },
  凰狩院琉璃: { normal: '凤翼炎姬', fallen: '烬凰妖姬' },
  太岁: { normal: '地凶星', fallen: '菌主' },
  妮妙·勒·菲: { normal: '湖光骑士', fallen: '叛逆骑士' },
  玉藻: { normal: '倾国魅狐', fallen: '灭国灾狐' },
  望月果心: { normal: '果心居士', fallen: '七宝行者' },
  本猫寺绫藏: { normal: '影瞬猫', fallen: '宵猫又' },
  星原樱: { normal: '墨染樱', fallen: '祭绯樱' },
  铃屋真凉: { normal: '冰碧玺', fallen: '霜欧泊' },
  芦屋道满: { normal: '白焰咒姬', fallen: '红莲咒鬼' },
  莫里娅蒂娜: { normal: '绮谋星', fallen: '黑蛛后' },
  诺查: { normal: '星曜瞳', fallen: '卡珊德拉' },
  无限自由: { normal: '天御机', fallen: '突击零式' },
};

// ── 别名映射: 世界书真名 → 变量中可能出现的别名列表 ──
//
// 当变量中的"真名"字段与世界书条目名不一致时,
// 需要通过别名进行匹配. 例如:
//   世界书条目名: `[角色]_小银-魔法少女`, 但变量真名可能是 "西娅"
//   世界书条目名: `[角色]_乌特迦·洛奇-魔法少女`, 但变量真名可能是 "乌特迦"
export const ALIAS_MAP: Record<string, string[]> = {
  小银: ['西娅'],
  乌特迦·洛奇: ['乌特迦', '洛奇'],
  妮妙·勒·菲: ['妮妙'],
};

// ── 工具函数 ──

/**
 * 根据真名和堕落状态查询对应的世界书魔法名.
 * @param trueName  变量中存储的真名（可能是别名）
 * @param isFallen  是否堕落 (true → 查堕落名, false → 查常态名)
 * @returns 映射表中找到的魔法名, 或 null
 */
export function getMagicNameForState(trueName: string, isFallen: boolean): string | null {
  const key = resolveWorldbookKey(trueName);
  const entry = MAGIC_NAME_MAP[key];
  if (!entry) return null;
  return isFallen ? entry.fallen : entry.normal;
}

/**
 * 将变量中可能出现的真名/别名解析为世界书条目中的标准真名.
 * 例如 "西娅" → "小银", "乌特迦" → "乌特迦·洛奇"
 */
export function resolveWorldbookKey(name: string): string {
  // 先尝试直接匹配
  if (MAGIC_NAME_MAP[name]) return name;

  // 再从别名映射中反向查找
  for (const [wbKey, aliases] of Object.entries(ALIAS_MAP)) {
    if (aliases.includes(name)) return wbKey;
  }

  return name; // 找不到则原样返回
}

/**
 * 扩展 worldbookProtectedNames: 对于每个世界书真名,
 * 将其别名也加入集合, 以便变量中的别名也能命中 protected 判断.
 */
export function expandProtectedNames(baseNames: Set<string>): Set<string> {
  const expanded = new Set(baseNames);
  for (const name of baseNames) {
    const aliases = ALIAS_MAP[name];
    if (aliases) {
      for (const alias of aliases) {
        expanded.add(alias);
      }
    }
  }
  // 同时将所有魔法名映射表中的真名也加入 (变量键名可能是真名)
  for (const wbKey of Object.keys(MAGIC_NAME_MAP)) {
    if (expanded.has(wbKey)) continue;
    // 检查世界书真名的别名是否已存在于 expanded 中
    const aliases = ALIAS_MAP[wbKey];
    if (aliases && aliases.some(a => expanded.has(a))) {
      expanded.add(wbKey);
    }
  }
  return expanded;
}
